  const handleSaveScale = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const date = formData.get('date') as string;

    // Extract selected employees and their specific services
    const assignments: Assignment[] = [];
    employees.forEach(emp => {
      const isChecked = formData.get(`check-${emp.id}`) === 'on';
      if (isChecked) {
        assignments.push({
          employeeId: emp.id,
          serviceType: formData.get(`service-${emp.id}`) as string
        });
      }
    });

    const existingIndex = scale.findIndex(s => s.date === date);
    if (existingIndex >= 0) {
      const newScale = [...scale];
      newScale[existingIndex] = { ...newScale[existingIndex], assignments };
      setScale(newScale);
    } else {
      setScale([...scale, { id: Math.random().toString(36).substr(2, 9), date, assignments }]);
    }
    setIsScaleModalOpen(false);
  };

