import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  CalendarDays, 
  ClipboardList, 
  UserX, 
  AlertTriangle, 
  BarChart3,
  Plus,
  ChevronLeft,
  ChevronRight,
  Filter,
  Download,
  Edit2,
  Trash2,
  Camera,
  Film,
  Scissors,
  Plane,
  PlayCircle,
  MinusCircle
} from 'lucide-react';
import { 
  Employee, 
  ScaleItem, 
  Absence, 
  Warning, 
  ViewTab, 
  EmployeeStatus, 
  WarningType,
  PeriodFilter,
  Assignment
} from './types';
import { 
  INITIAL_EMPLOYEES, 
  INITIAL_SCALE, 
  INITIAL_ABSENCES, 
