  variant?: 'primary' | 'secondary' | 'danger' | 'ghost' | 'warning',
  className?: string,
  disabled?: boolean,
  type?: 'button' | 'submit'
}> = ({ children, onClick, variant = 'primary', className = "", disabled, type = 'button' }) => {
  const variants = {
    primary: 'bg-blue-600 text-white active:bg-blue-700',
