      <main className="flex-1 px-6 pt-2">
        {activeTab === 'dashboard' && renderDashboard()}
        {activeTab === 'employees' && renderEmployees()}
        {activeTab === 'scale' && renderScale()}
        {activeTab === 'services' && renderServices()}
        {activeTab === 'absences' && (
          <div className="space-y-8 pb-24">
