  const renderReports = () => {
    const filteredScale = scale.filter(s => isWithinInterval(new Date(s.date + 'T12:00:00'), currentRange));
    const generalStats = {
      [AssignmentStatus.COMPLETED]: 0,
      [AssignmentStatus.CANCELLED]: 0,
      [AssignmentStatus.RESCHEDULED]: 0,
